-- =================================================================
-- SQL Data Import for ScaleBiz White-Label Application
-- =================================================================
-- This script populates the database with initial data for all stores.
-- It is designed to be idempotent, meaning it can be run multiple times
-- without creating duplicate entries.

-- Select the database to use
USE scalebiz_db;

-- Temporarily disable foreign key checks to allow for easy truncation and insertion
SET FOREIGN_KEY_CHECKS=0;

-- =================================================================
-- Truncate Tables
-- Description: Clears all existing data to ensure a clean import.
-- =================================================================
TRUNCATE TABLE store_configurations;
TRUNCATE TABLE product_categories;
TRUNCATE TABLE categories;
TRUNCATE TABLE products;
TRUNCATE TABLE users;
TRUNCATE TABLE pages;
TRUNCATE TABLE orders;
TRUNCATE TABLE order_items;
TRUNCATE TABLE stores;

